-- Create "role_data_scopes" table
CREATE TABLE "role_data_scopes" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "resource_type" character varying NOT NULL,
  "mode" character varying NOT NULL,
  "resource_ids" jsonb NOT NULL DEFAULT '[]',
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "role_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "role_data_scopes_roles_data_scopes" FOREIGN KEY ("role_id") REFERENCES "roles" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "role_data_scopes_mode_allowed" CHECK ((mode)::text = ANY ((ARRAY['ALL'::character varying, 'ASSIGNED'::character varying, 'NONE'::character varying])::text[])),
  CONSTRAINT "role_data_scopes_resource_type_allowed" CHECK ((resource_type)::text = 'warehouse'::text)
);
-- Create index "roledatascope_resource_type_mode" to table: "role_data_scopes"
CREATE INDEX "roledatascope_resource_type_mode" ON "role_data_scopes" ("resource_type", "mode");
-- Create index "roledatascope_role_id_resource_type" to table: "role_data_scopes"
CREATE UNIQUE INDEX "roledatascope_role_id_resource_type" ON "role_data_scopes" ("role_id", "resource_type");

-- Existing business roles receive an explicit warehouse scope. Warehouse and
-- quality freeze the warehouse ids that exist at migration time; later
-- warehouses require an explicit scope update. Missing/custom roles fail closed.
INSERT INTO "role_data_scopes" ("resource_type", "mode", "resource_ids", "created_at", "updated_at", "role_id")
SELECT
  'warehouse',
  CASE
    WHEN r."role_key" IN ('boss', 'sales', 'pmc', 'purchase', 'finance', 'production') THEN 'ALL'
    WHEN r."role_key" IN ('warehouse', 'quality') AND EXISTS (SELECT 1 FROM "warehouses") THEN 'ASSIGNED'
    ELSE 'NONE'
  END,
  CASE
    WHEN r."role_key" IN ('warehouse', 'quality')
      THEN COALESCE((SELECT jsonb_agg(w."id" ORDER BY w."id") FROM "warehouses" AS w), '[]'::jsonb)
    ELSE '[]'::jsonb
  END,
  CURRENT_TIMESTAMP,
  CURRENT_TIMESTAMP,
  r."id"
FROM "roles" AS r;
